     1→import { z } from 'zod';
     2→import { EmailMessage, StrongIndicatorResult } from '../types';
     3→import {
     4→  extractDomainFromEmail,
     5→  findMatchingDomain,
     6→  findMatchingKeywords,
     7→  extractTextFromHtml,
     8→} from '../utils/email-utils';
     9→import { ClassificationContext } from './types';
    10→
    11→/**
    12→ * Strong Indicators Stage
    13→ *
    14→ * Implements diminishing returns seeding per SCORING_LOGIC.md "Strong Indicator Seeding" section.
    15→ * High-weight signals that provide strong category hints, applied with diminishing returns
    16→ * across multiple dimensions (subject, from_domain, body).
    17→ *
    18→ * Logic:
    19→ * - seed = Σ weighted_matches
    20→ * - Diminishing returns per dimension: first full, rest * 0.5
    21→ * - strong_indicator_seed = max(existing_seed, seed)
    22→ * - Applied after hard assertions before subtype accumulation
    23→ */
    24→
    25→export interface StrongIndicatorConfig {
    26→  from_domains_ref?: {
    27→    source_group: string;
    28→    confidence: 'high' | 'medium';
    29→  };
    30→  subject_contains?: string[];
    31→  body_contains?: string[];
    32→}
    33→
    34→export interface StrongIndicatorStageConfig {
    35→  confidenceThresholds: {
    36→    high_confidence: number;
    37→    medium_confidence: number;
    38→    low_confidence: number;
    39→  };
    40→  categorySignals: Record<string, { strong_indicators?: StrongIndicatorConfig }>;
    41→  domainLookup: Record<
    42→    string,
    43→    {
    44→      high_confidence: Array<{ domain: string; type?: string }>;
    45→      medium_confidence: Array<{ domain: string; type?: string }>;
    46→      low_confidence: Array<{ domain: string; type?: string }>;
    47→    }
    48→  >;
    49→  // Weight for strong indicators (typically 8-12 range for medium-high confidence)
    50→  strongIndicatorBaseWeight: number;
    51→  // Diminishing returns factor for subsequent matches in same dimension
    52→  diminishingReturnsFactor: number;
    53→}
    54→
    55→export interface StrongIndicatorStageResult {
    56→  categoriesWithStrongIndicators: string[];
    57→  indicatorResults: StrongIndicatorResult[];
    58→  updatedSeeds: Record<string, number>;
    59→  processingDurationMs: number;
    60→}
    61→
    62→/**
    63→ * Executes strong indicators stage of email classification
    64→ *
    65→ * @param email The email message to classify
    66→ * @param context Current classification context with category scores and seeds
    67→ * @param config Configuration containing category signals and thresholds
    68→ * @returns Strong indicator results and updated seed scores
    69→ */
    70→export function executeStrongIndicators(
    71→  email: EmailMessage,
    72→  context: ClassificationContext,
    73→  config: StrongIndicatorStageConfig
    74→): StrongIndicatorStageResult {
    75→  const startTime = Date.now();
    76→  const categoriesWithStrongIndicators: string[] = [];
    77→  const indicatorResults: StrongIndicatorResult[] = [];
    78→  const updatedSeeds: Record<string, number> = { ...context.strongIndicatorSeeds };
    79→
    80→  const baseWeight = config.strongIndicatorBaseWeight;
    81→  const diminishingFactor = config.diminishingReturnsFactor;
    82→
    83→  // Process each category that has strong indicators configured
    84→  for (const [categoryName, categoryConfig] of Object.entries(config.categorySignals)) {
    85→    if (!categoryConfig.strong_indicators) {
    86→      continue;
    87→    }
    88→
    89→    const strongIndicators = categoryConfig.strong_indicators;
    90→    const existingSeed = updatedSeeds[categoryName] || 0;
    91→    let categoryHadIndicator = false;
    92→    let newSeedScore = existingSeed;
    93→
    94→    // Track matches per dimension for diminishing returns
    95→    const dimensionMatches = {
    96→      from_domain: 0,
    97→      subject_contains: 0,
    98→      body_contains: 0,
    99→    };
   100→
   101→    // Check from_domains_ref (domain-based strong indicators)
   102→    if (strongIndicators.from_domains_ref) {
   103→      const { source_group, confidence } = strongIndicators.from_domains_ref;
   104→
   105→      const domainGroup = config.domainLookup[source_group];
   106→      if (domainGroup) {
   107→        const emailDomain = extractDomainFromEmail(email.from.email);
   108→        const matchedDomain = findMatchingDomain(emailDomain, domainGroup, confidence);
   109→
   110→        if (matchedDomain) {
   111→          dimensionMatches.from_domain++;
   112→          const isFirstMatch = dimensionMatches.from_domain === 1;
   113→          const effectiveWeight = isFirstMatch ? baseWeight : baseWeight * diminishingFactor;
   114→          const proposedSeed = newSeedScore + effectiveWeight;
   115→
   116→          indicatorResults.push({
   117→            category: categoryName,
   118→            indicatorType: 'from_domain',
   119→            matchedValue: matchedDomain.domain,
   120→            seedScore: effectiveWeight,
   121→            diminishingReturnsApplied: !isFirstMatch,
   122→            existingSeedScore: newSeedScore,
   123→            finalSeedScore: proposedSeed,
   124→            reason: `Email from domain '${emailDomain}' matches ${confidence}-confidence domain '${matchedDomain.domain}' in group '${source_group}'. Weight: ${effectiveWeight} (${isFirstMatch ? 'full' : 'diminished'})`,
   125→          });
   126→
   127→          newSeedScore = Math.max(newSeedScore, proposedSeed);
   128→          categoryHadIndicator = true;
   129→        }
   130→      }
   131→    }
   132→
   133→    // Check subject_contains
   134→    if (strongIndicators.subject_contains && email.subject) {
   135→      const matchedKeywords = findMatchingKeywords(email.subject, strongIndicators.subject_contains);
   136→
   137→      for (const keyword of matchedKeywords) {
   138→        dimensionMatches.subject_contains++;
   139→        const isFirstMatch = dimensionMatches.subject_contains === 1;
   140→        const effectiveWeight = isFirstMatch ? baseWeight : baseWeight * diminishingFactor;
   141→        const proposedSeed = newSeedScore + effectiveWeight;
   142→
   143→        indicatorResults.push({
   144→          category: categoryName,
   145→          indicatorType: 'subject_contains',
   146→          matchedValue: keyword,
   147→          seedScore: effectiveWeight,
   148→          diminishingReturnsApplied: !isFirstMatch,
   149→          existingSeedScore: newSeedScore,
   150→          finalSeedScore: proposedSeed,
   151→          reason: `Subject '${email.subject}' contains strong indicator keyword '${keyword}'. Weight: ${effectiveWeight} (${isFirstMatch ? 'full' : 'diminished'})`,
   152→        });
   153→
   154→        newSeedScore = Math.max(newSeedScore, proposedSeed);
   155→        categoryHadIndicator = true;
   156→      }
   157→    }
   158→
   159→    // Check body_contains
   160→    if (strongIndicators.body_contains && (email.bodyPlain || email.bodyHtml)) {
   161→      // Use plain text body if available, otherwise extract from HTML
   162→      const bodyText = email.bodyPlain || extractTextFromHtml(email.bodyHtml || '');
   163→      const matchedKeywords = findMatchingKeywords(bodyText, strongIndicators.body_contains);
   164→
   165→      for (const keyword of matchedKeywords) {
   166→        dimensionMatches.body_contains++;
   167→        const isFirstMatch = dimensionMatches.body_contains === 1;
   168→        const effectiveWeight = isFirstMatch ? baseWeight : baseWeight * diminishingFactor;
   169→        const proposedSeed = newSeedScore + effectiveWeight;
   170→
   171→        indicatorResults.push({
   172→          category: categoryName,
   173→          indicatorType: 'body_contains',
   174→          matchedValue: keyword,
   175→          seedScore: effectiveWeight,
   176→          diminishingReturnsApplied: !isFirstMatch,
   177→          existingSeedScore: newSeedScore,
   178→          finalSeedScore: proposedSeed,
   179→          reason: `Body text contains strong indicator keyword '${keyword}'. Weight: ${effectiveWeight} (${isFirstMatch ? 'full' : 'diminished'})`,
   180→        });
   181→
   182→        newSeedScore = Math.max(newSeedScore, proposedSeed);
   183→        categoryHadIndicator = true;
   184→      }
   185→    }
   186→
   187→    // Update seed score using max logic (strong_indicator_seed = max(existing_seed, seed))
   188→    if (categoryHadIndicator) {
   189→      updatedSeeds[categoryName] = newSeedScore;
   190→      categoriesWithStrongIndicators.push(categoryName);
   191→    }
   192→  }
   193→
   194→  const processingDurationMs = Date.now() - startTime;
   195→
   196→  // Update context tracking
   197→  context.stageTimings['strong_indicators'] = processingDurationMs;
   198→  context.configurationRefs['strong_indicators'] = 'category_signals.*.strong_indicators';
   199→  context.strongIndicatorSeeds = updatedSeeds;
   200→
   201→  return {
   202→    categoriesWithStrongIndicators,
   203→    indicatorResults,
   204→    updatedSeeds,
   205→    processingDurationMs,
   206→  };
   207→}
   208→
   209→/**
   210→ * Zod schema for validating strong indicator configuration
   211→ */
   212→export const StrongIndicatorConfigSchema = z
   213→  .object({
   214→    from_domains_ref: z
   215→      .object({
   216→        source_group: z.string(),
   217→        confidence: z.enum(['high', 'medium']),
   218→      })
