     8→ * "Attribute Detectors & Derived Attributes" section.
     9→ */
    10→
    11→import { EmailMessage, ProcessingConfig, AttributeDetector, DerivedAttribute } from '../types';
    12→import { ClassificationContext } from './types';
    13→
    14→/**
    15→ * Individual detected attribute result
    16→ */
    17→export interface DetectedAttribute {
    18→  attribute_name: string;
    19→  attribute_value: boolean | string | number;
    20→  detection_method: 'pattern' | 'derived' | 'domain_lookup';
    21→  detection_evidence: string;
