    57→    logistics_domains?: string[];
    58→  };
    59→}
    60→
    61→/**
    62→ * Execute attribute detection stage function
    63→ */
    64→export function executeAttributeDetection(
    65→  email: EmailMessage,
    66→  context: ClassificationContext,
    67→  config: AttributeDetectionStageConfig
    68→): AttributeDetectionResult {
    69→  const startTime = Date.now();
    70→  const detectedAttributes: DetectedAttribute[] = [];
    71→
    72→  // Apply pattern-based detectors
    73→  const patternAttributes = detectPatternAttributes(email, config);
    74→  detectedAttributes.push(...patternAttributes);
    75→
    76→  // Apply derived attribute logic
    77→  const derivedAttributes = detectDerivedAttributes(email, config);
    78→  detectedAttributes.push(...derivedAttributes);
    79→
    80→  const processingTime = Math.max(1, Date.now() - startTime); // Ensure minimum 1ms
    81→
    82→  // Update context with stage timing
    83→  context.stageTimings['attribute_detection'] = processingTime;
    84→
    85→  return {
    86→    detected_attributes: detectedAttributes,
    87→    processing_duration_ms: processingTime,
    88→    parallel_processed: true,
