   341→    const thresholdType = config.defaultArchiveThreshold;
   342→    const thresholdValue = config.archiveThresholds[thresholdType];
   343→    const confidence = aiClassificationResult.confidence;
   344→    const belowThreshold = confidence < thresholdValue;
   345→
   346→    thresholdEvaluation = {
   347→      thresholdType,
   348→      thresholdUsed: thresholdValue,
   349→      confidenceScore: confidence,
   350→      belowThreshold,
   351→      evaluationReason: `Confidence ${confidence.toFixed(2)} ${belowThreshold ? '<' : '>='} ${thresholdType} threshold ${thresholdValue}`,
   352→    };
   353→
   354→    processingSteps.push(
   355→      `Threshold evaluation: ${confidence.toFixed(2)} ${belowThreshold ? 'below' : 'above'} ${thresholdType} (${thresholdValue})`
   356→    );
   357→
   358→    if (belowThreshold) {
   359→      determinedActions.push('archive');
   360→      actionReasons.push(`Confidence ${confidence.toFixed(2)} below threshold ${thresholdValue}`);
   361→      processingSteps.push('Action: archive (below threshold)');
   362→
   363→      // Mark as read if archiving
   364→      if (actionSettings.markAsReadIfArchived) {
   365→        determinedActions.push('mark_as_read');
   366→        actionReasons.push('Mark as read when archiving');
   367→        processingSteps.push('Action: mark_as_read (archiving)');
   368→      }
   369→    }
   370→  }
   371→
   372→  // Apply custom category-specific actions
   373→  if (actionSettings.applyCustomActions && config.categoryActions) {
   374→    const allCategories = [assignedLabels.primary, ...assignedLabels.secondary];
   375→
   376→    for (const category of allCategories) {
   377→      const categoryActions = config.categoryActions[category];
   378→      if (categoryActions && Array.isArray(categoryActions)) {
   379→        for (const action of categoryActions) {
   380→          if (!determinedActions.includes(action)) {
   381→            determinedActions.push(action);
   382→            actionReasons.push(`Category ${category} action: ${action}`);
   383→            processingSteps.push(`Action: ${action} (from category ${category})`);
   384→          }
   385→        }
   386→      }
   387→    }
   388→  }
   389→
   390→  const actionReasoning = actionReasons.length > 0 ? actionReasons.join('; ') : 'No actions determined';
   391→
   392→  return { determinedActions, actionReasoning, thresholdEvaluation };
   393→}
