/**
 * Shared Types for Classification Stages
 *
 * Common interfaces used across multiple classification pipeline stages.
 */

/**
 * Classification context shared across all pipeline stages
 * Tracks the current state of email classification including scores,
 * applied stages, and performance metrics.
 */
export interface ClassificationContext {
  emailId: string;
  sessionId: string;
  categoryScores: Record<string, number>;
  hardAssertionsApplied: string[];
  strongIndicatorSeeds: Record<string, number>;
  stageTimings: Record<string, number>;
  configurationRefs: Record<string, string>;
}

/**
 * Multi-label selection types for stage configuration and results
 */

export interface CategoryScore {
  score: number;
  confidence: number;
  rationale: string;
  selectedSubtypeId?: string | null;
  decision?: 'positive' | 'candidate' | 'rejected';
  decisionRationale?: string;
  scoringComponents?: Record<string, number | string | boolean>;
}

export interface MultiLabelConfig {
  maxLabels: number;
  minSecondaryConfidence: number;
  allowedCombinations: string[];
  strictCombinationMode?: boolean;
}

export interface ConfidenceThresholds {
  highConfidence: number;
  mediumConfidence: number;
  lowConfidence: number;
  secondaryLabelMinGap: number;
}

export interface SelectedLabel {
  category: string;
  subtype?: string | null;
  confidence: number;
  score: number;
  isPrimary: boolean;
  labelOrder: number;
  selectionRationale: string;
}

export interface SelectionSummary {
  totalLabels: number;
  primaryCategory: string | null;
  confidenceRange: [number, number];
  selectionMethod: 'single_label' | 'multi_label' | 'none_selected';
  needsAi: boolean;
  topCategories?: Array<{
    category: string;
    score: number;
  }>;
}

export interface MultiLabelSelectionResult {
  selectedLabels: SelectedLabel[];
  needsAiClassification: boolean;
  selectionSummary: SelectionSummary;
  processingDurationMs: number;
}

/**
 * Type definitions for the Email Classification Engine
 *
 * This module exports all entity types for the sophisticated 9-stage
 * classification pipeline with parallel processing capabilities.
 */

// Core email processing entities
export * from './email-message';
export * from './classification-session';
export * from './email-classification';

// Explainability and audit trail entities
export * from './explainability-trace';
export * from './score-breakdown';
export * from './attribute-context';

// Configuration and schema validation
export * from './category-configuration';

// Re-export commonly used types for convenience
export type { EmailMessage, EmailProcessingState } from './email-message';

export type { ClassificationSession, ProcessingMode, SessionPerformanceMetrics } from './classification-session';

export type {
  EmailClassification,
  ConfidenceLevel,
  CategoryAssignmentType,
  DetailedClassificationResult,
} from './email-classification';

export type { ExplainabilityTrace, CompleteExplainabilityTrace } from './explainability-trace';

export type { ScoreBreakdown, CategoryScoreDetails, DetailedScoreBreakdown } from './score-breakdown';

export type { AttributeContext, AttributeRole, ExtendedAttributeContext } from './attribute-context';

export type {
  CategoryConfiguration,
  ProcessingConfig,
  ValidatedCategoryConfiguration,
  AttributeDetector,
  DerivedAttribute,
} from './category-configuration';

// Stage result types
export type { AttributeDetectionResult, DetectedAttribute } from '../stages/attribute-detection';

// Multi-label selection types
export type {
  CategoryScore,
  MultiLabelConfig,
  ConfidenceThresholds,
  SelectedLabel,
  SelectionSummary,
  MultiLabelSelectionResult,
} from '../stages/types';

// API types for REST endpoints (with explicit exports to avoid conflicts)
export type {
  EmailContent,
  BatchClassificationRequest,
  BatchClassificationResponse,
  BatchClassificationResult,
  SingleClassificationRequest,
  SingleClassificationResponse,
  ConfigValidationRequest,
  ConfigValidationResponse,
  ValidationError,
  ValidationWarning,
} from './api-types';

// Re-export CompiledRule and ClassificationError from API types to resolve conflicts
export type { CompiledRule as APICompiledRule, ClassificationError as APIClassificationError } from './api-types';

